  1513→    for (const block of blocks) {
  1514→      if (isUserBlock(block)) {
  1515→        // Start a new turn
  1516→        if (currentTurn) {
  1517→          this.finalizeChunk(currentTurn, blocks);
  1518→          chunks.push(currentTurn);
  1519→        }
  1520→        currentTurn = this.createChunk('turn', this.getTurnLabel(block));
  1521→        currentTurn.blockIds.push(block.id);
  1522→        currentAgentId = null;
  1523→      } else if (isAgentBlock(block)) {
  1524→        if (!currentTurn) {
  1525→          // Agent without preceding user (e.g., system prompt response)
  1526→          currentTurn = this.createChunk('turn', 'Agent response');
  1527→        }
  1528→        currentTurn.blockIds.push(block.id);
  1529→        currentAgentId = block.id;
  1530→      } else if ((isToolBlock(block) || isMcpBlock(block)) && currentTurn) {
  1531→        currentTurn.blockIds.push(block.id);
  1532→      }
  1533→    }
  1534→
  1535→    // Don't forget the last turn
  1536→    if (currentTurn) {
  1537→      this.finalizeChunk(currentTurn, blocks);
  1538→      chunks.push(currentTurn);
  1539→    }
  1540→
  1541→    return chunks;
  1542→  }
  1543→
  1544→  private createChunk(level: ChunkLevel, label: string): Chunk {
  1545→    return {
  1546→      id: `chunk-${++this.chunkIdCounter}`,
  1547→      level,
  1548→      label,
  1549→      blockIds: [],
  1550→      childChunkIds: [],
  1551→      totalTokensIn: 0,
  1552→      totalTokensOut: 0,
  1553→      totalWallTimeMs: 0,
  1554→    };
  1555→  }
  1556→
  1557→  private getTurnLabel(userBlock: AnyBlock): string {
