  1570→    chunk.totalTokensOut = chunkBlocks.reduce((sum, b) => sum + (b.tokensOut || 0), 0);
  1571→    chunk.totalWallTimeMs = chunkBlocks.reduce((sum, b) => sum + (b.wallTimeMs || 0), 0);
  1572→  }
